import {
  BarChart3,
  FileText,
  LayoutGrid,
  Home,
  Settings,
  Users
} from "lucide-react";

const SIDEBAR_ICONS = [Home, LayoutGrid, Users, BarChart3, FileText, Settings];

const TABS = ["Overview", "Candidates", "Insights", "Benchmarking"];

const SKILLS = [
  { label: "Financial Modeling", pct: 92 },
  { label: "Data Analysis", pct: 88 },
  { label: "Business Judgment", pct: 84 },
  { label: "Communication", pct: 76 },
  { label: "Stakeholder Mgmt", pct: 72 }
];

const CANDIDATES = [
  { tag: "A", name: "Candidate A", score: 92, skill: "Financial Modeling", decision: "Strong signal", tone: "good" },
  { tag: "B", name: "Candidate B", score: 86, skill: "Data Analysis", decision: "Strong signal", tone: "good" },
  { tag: "C", name: "Candidate C", score: 75, skill: "Business Judgment", decision: "Review", tone: "watch" }
] as const;

const TREND = [58, 62, 60, 67, 64, 72, 76, 74, 81, 86];

function buildPath(points: number[], width: number, height: number) {
  const max = 100;
  const min = 45;
  const step = width / (points.length - 1);
  const coords = points.map((value, index) => {
    const x = index * step;
    const y = height - ((value - min) / (max - min)) * height;
    return [x, y] as const;
  });
  const line = coords
    .map(([x, y], index) => `${index === 0 ? "M" : "L"} ${x.toFixed(1)} ${y.toFixed(1)}`)
    .join(" ");
  const area = `${line} L ${width} ${height} L 0 ${height} Z`;
  return { line, area };
}

export default function HeroDashboard() {
  const { line, area } = buildPath(TREND, 320, 120);

  return (
    <div className="relative z-[4] flex h-full overflow-hidden">
      <aside className="hidden w-[46px] shrink-0 flex-col items-center gap-1 border-r border-white/[0.06] bg-black/25 py-4 sm:flex">
        <span className="mb-3 flex h-7 w-7 items-center justify-center rounded-lg bg-gradient-to-br from-[#7c5cff] to-[#5b8cff]">
          <span className="h-2.5 w-2.5 rounded-full border-2 border-white" />
        </span>
        {SIDEBAR_ICONS.map((Icon, index) => (
          <span
            key={index}
            className={`flex h-8 w-8 items-center justify-center rounded-lg ${
              index === 0 ? "bg-white/[0.08] text-white" : "text-white/35"
            }`}
          >
            <Icon className="h-4 w-4" strokeWidth={1.8} />
          </span>
        ))}
      </aside>

      <div className="flex min-w-0 flex-1 flex-col p-4 sm:p-5">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <p className="text-[13px] font-bold text-white">Financial Analyst Simulation</p>
            <span className="inline-flex items-center gap-1.5 rounded-full border border-[#3dd68c]/25 bg-[#3dd68c]/10 px-2 py-0.5 text-[9px] font-bold uppercase tracking-[0.1em] text-[#3dd68c]">
              <span className="h-1.5 w-1.5 animate-pulse-dot rounded-full bg-[#3dd68c]" />
              Active
            </span>
          </div>
          <span className="hidden text-[10px] font-semibold text-white/40 md:inline">Last 30 days</span>
        </div>

        <div className="mt-3 flex items-center gap-4 border-b border-white/[0.07] pb-2.5 text-[11px] font-semibold">
          {TABS.map((tab, index) => (
            <span key={tab} className={index === 0 ? "relative text-white" : "text-white/40"}>
              {tab}
              {index === 0 && <span className="absolute -bottom-[11px] left-0 h-px w-full bg-gradient-to-r from-[#5b8cff] to-[#9b5cff]" />}
            </span>
          ))}
        </div>

        <div className="mt-4 grid flex-1 grid-cols-1 gap-3 lg:grid-cols-[1.35fr_1fr]">
          <div className="rounded-2xl border border-white/[0.08] bg-black/25 p-3.5">
            <div className="flex items-end justify-between">
              <div>
                <p className="text-[10px] font-semibold uppercase tracking-[0.12em] text-white/40">Simulation performance</p>
                <p className="mt-1 flex items-center gap-2">
                  <span className="tabular-nums text-[26px] font-extrabold leading-none text-white">86%</span>
                  <span className="rounded-md bg-[#3dd68c]/12 px-1.5 py-0.5 text-[10px] font-bold text-[#3dd68c]">+24%</span>
                </p>
              </div>
            </div>
            <div className="mt-3 h-[88px]">
              <svg viewBox="0 0 320 120" className="h-full w-full" preserveAspectRatio="none" aria-hidden>
                <defs>
                  <linearGradient id="hdFill" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor="rgba(124,92,255,0.34)" />
                    <stop offset="100%" stopColor="rgba(124,92,255,0)" />
                  </linearGradient>
                  <linearGradient id="hdLine" x1="0" y1="0" x2="1" y2="0">
                    <stop offset="0%" stopColor="#5b8cff" />
                    <stop offset="100%" stopColor="#9b5cff" />
                  </linearGradient>
                </defs>
                <path d={area} fill="url(#hdFill)" />
                <path
                  className="hero-draw"
                  d={line}
                  fill="none"
                  stroke="url(#hdLine)"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
            <div className="mt-1 flex justify-between text-[8.5px] font-medium text-white/30">
              {["Apr 12", "Apr 26", "May 10", "May 24", "Jun 7"].map((m) => (
                <span key={m}>{m}</span>
              ))}
            </div>
          </div>

          <div className="rounded-2xl border border-white/[0.08] bg-black/25 p-3.5">
            <p className="text-[10px] font-semibold uppercase tracking-[0.12em] text-white/40">Top skill areas</p>
            <div className="mt-3 space-y-2.5">
              {SKILLS.map((skill, index) => (
                <div key={skill.label}>
                  <div className="flex items-center justify-between text-[10.5px]">
                    <span className="font-medium text-white/72">{skill.label}</span>
                    <span className="tabular-nums font-bold text-white">{skill.pct}%</span>
                  </div>
                  <div className="mt-1 h-1 overflow-hidden rounded-full bg-white/[0.07]">
                    <div
                      className="hero-grow h-full rounded-full bg-gradient-to-r from-[#5b8cff] to-[#9b5cff]"
                      style={{ width: `${skill.pct}%`, animationDelay: `${0.7 + index * 0.12}s` }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-3 rounded-2xl border border-white/[0.08] bg-black/25 p-3.5">
          <div className="flex items-center justify-between">
            <p className="text-[10px] font-semibold uppercase tracking-[0.12em] text-white/40">Top candidates</p>
            <span className="text-[9px] font-semibold text-white/30">Evidence scored</span>
          </div>
          <div className="mt-2.5 space-y-1.5">
            {CANDIDATES.map((candidate) => (
              <div key={candidate.name} className="grid grid-cols-[auto_1fr_auto_auto] items-center gap-3 text-[11px]">
                <span className="flex h-5 w-5 items-center justify-center rounded-md border border-white/[0.1] bg-white/[0.04] text-[10px] font-bold text-white/70">
                  {candidate.tag}
                </span>
                <span className="truncate font-semibold text-white">{candidate.name}</span>
                <span className="hidden text-white/45 sm:inline">{candidate.skill}</span>
                <span className="flex items-center gap-2">
                  <span className="tabular-nums font-bold text-white">{candidate.score}</span>
                  <span
                    className={`rounded-md px-1.5 py-0.5 text-[9px] font-bold ${
                      candidate.tone === "good"
                        ? "bg-[#3dd68c]/12 text-[#3dd68c]"
                        : "bg-[#f5b942]/12 text-[#f5b942]"
                    }`}
                  >
                    {candidate.decision}
                  </span>
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
