"use client";

import { useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useScroll, useMotionValueEvent } from "motion/react";
import { ArrowRight, ChevronDown, Menu, X } from "lucide-react";
import FydellBrand from "@/components/brand/FydellBrand";

const LINKS = [
  { label: "Product", href: "/#product", match: "/", caret: true },
  { label: "Solutions", href: "/solutions", match: "/solutions", caret: true },
  { label: "Resources", href: "/resources", match: "/resources", caret: true },
  { label: "Company", href: "/company", match: "/company", caret: true },
  { label: "Pricing", href: "/pricing", match: "/pricing", caret: false }
];

export default function SiteNav() {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const pathname = usePathname();
  const { scrollY } = useScroll();

  useMotionValueEvent(scrollY, "change", (latest) => {
    const next = latest > 12;
    setScrolled((prev) => (prev === next ? prev : next));
  });

  return (
    <header className="fixed inset-x-0 top-0 z-50">
      <div
        className={`border-b transition-[background-color,border-color,box-shadow,backdrop-filter] duration-500 ${
          scrolled
            ? "border-white/[0.09] bg-[#03050d]/[0.82] shadow-[0_18px_50px_-24px_rgba(0,0,0,0.9)] backdrop-blur-[26px] backdrop-saturate-150"
            : "border-transparent bg-[#03050d]/30 backdrop-blur-[10px]"
        }`}
      >
        <div className="mx-auto grid h-[76px] max-w-[1536px] grid-cols-[1fr_auto_1fr] items-center gap-6 px-6 lg:px-12">
          <FydellBrand markSize={38} sheen className="justify-self-start" />

          <nav className="hidden items-center justify-center gap-9 lg:flex" aria-label="Primary navigation">
            {LINKS.map((item) => {
              const active = pathname === item.match;
              return (
                <Link
                  key={item.label}
                  href={item.href}
                  className={`group relative inline-flex h-[76px] items-center gap-1 text-[15px] font-semibold transition hover:text-white ${
                    active ? "text-white" : "text-white/75"
                  }`}
                >
                  {item.label}
                  {item.caret && (
                    <ChevronDown className="h-3.5 w-3.5 opacity-55 transition group-hover:opacity-85" strokeWidth={2} />
                  )}
                  <span
                    className={`absolute bottom-0 left-1/2 h-px -translate-x-1/2 rounded-full bg-gradient-to-r from-[#5b8cff] to-[#9b5cff] transition-all ${
                      active ? "w-9 opacity-100" : "w-0 opacity-0 group-hover:w-7 group-hover:opacity-80"
                    }`}
                  />
                </Link>
              );
            })}
          </nav>

          <div className="flex items-center justify-end gap-5">
            <Link href="/login" className="hidden text-[15px] font-semibold text-white/78 transition hover:text-white sm:inline-flex">
              Log in
            </Link>
            <Link
              href="/signup"
              className="btn-lift hidden h-11 items-center gap-2.5 rounded-xl bg-gradient-to-r from-[#7c5cff] to-[#5b8cff] px-6 text-[15px] font-bold text-white shadow-[0_14px_42px_rgba(124,92,255,0.35)] hover:brightness-110 sm:inline-flex"
            >
              Book a demo
              <ArrowRight className="h-4 w-4" />
            </Link>
            <button
              type="button"
              onClick={() => setOpen((value) => !value)}
              aria-label="Menu"
              aria-expanded={open}
              className="flex h-11 w-11 items-center justify-center rounded-xl border border-white/[0.1] bg-white/[0.035] text-white lg:hidden"
            >
              {open ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
            </button>
          </div>
        </div>
      </div>

      {open && (
        <div className="border-b border-white/[0.08] bg-[#03050d]/95 px-6 py-5 shadow-2xl backdrop-blur-2xl lg:hidden">
          <nav className="mx-auto flex max-w-[1536px] flex-col gap-1" aria-label="Mobile navigation">
            {LINKS.map((item) => (
              <Link
                key={item.label}
                href={item.href}
                onClick={() => setOpen(false)}
                className="rounded-xl px-3 py-3 text-[15px] font-semibold text-white/82 transition hover:bg-white/[0.05] hover:text-white"
              >
                {item.label}
              </Link>
            ))}
            <Link
              href="/login"
              onClick={() => setOpen(false)}
              className="rounded-xl px-3 py-3 text-[15px] font-semibold text-white/82 transition hover:bg-white/[0.05] hover:text-white sm:hidden"
            >
              Log in
            </Link>
            <Link
              href="/signup"
              onClick={() => setOpen(false)}
              className="mt-3 flex h-11 items-center justify-center rounded-xl bg-gradient-to-r from-[#7c5cff] to-[#5b8cff] text-[15px] font-bold text-white"
            >
              Book a demo
              <ArrowRight className="ml-2 h-4 w-4" />
            </Link>
          </nav>
        </div>
      )}
    </header>
  );
}
